DROP TABLE IF EXISTS `cbs_certification_types`;
CREATE TABLE IF NOT EXISTS `cbs_certification_types` (
  `iid` int(11) NOT NULL AUTO_INCREMENT,
  `iname` varchar(50) DEFAULT NULL,
  `comments` varchar(50) DEFAULT NULL,
  `amount` int(11) NOT NULL DEFAULT 0,
  `body_text` varchar(1024) NOT NULL DEFAULT '<insert text here>',
  `lgu_type_id` int(11) NOT NULL DEFAULT 1,
  PRIMARY KEY (`iid`),
  UNIQUE KEY `iname` (`iname`),
  KEY `lgu_type_id` (`lgu_type_id`),
  CONSTRAINT `cbs_certification_types_ibfk_1` FOREIGN KEY (`lgu_type_id`) REFERENCES `lgu_types` (`iid`)
) ENGINE=InnoDB AUTO_INCREMENT=18 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;

